CREATE TABLE file_asset(id BIGINT PRIMARY KEY AUTO_INCREMENT,asset_no VARCHAR(64) NOT NULL,bucket_name VARCHAR(128) NOT NULL,object_key VARCHAR(512) NOT NULL,original_name VARCHAR(255) NOT NULL,content_type VARCHAR(128) NOT NULL,size_bytes BIGINT NOT NULL,sha256 CHAR(64) NOT NULL,status VARCHAR(32) NOT NULL,created_at DATETIME(3) NOT NULL,UNIQUE KEY uk_asset_no(asset_no),UNIQUE KEY uk_asset_object(bucket_name,object_key));
CREATE TABLE import_batch(id BIGINT PRIMARY KEY AUTO_INCREMENT,batch_no VARCHAR(64) NOT NULL,asset_id BIGINT NOT NULL,business_type VARCHAR(64) NOT NULL,template_version VARCHAR(32) NOT NULL,status VARCHAR(32) NOT NULL,total_rows INT NOT NULL DEFAULT 0,success_rows INT NOT NULL DEFAULT 0,error_rows INT NOT NULL DEFAULT 0,failure_reason VARCHAR(1000),version INT NOT NULL DEFAULT 0,created_at DATETIME(3) NOT NULL,updated_at DATETIME(3) NOT NULL,UNIQUE KEY uk_batch_no(batch_no),KEY idx_import_status(status,created_at));
CREATE TABLE import_error(id BIGINT PRIMARY KEY AUTO_INCREMENT,batch_id BIGINT NOT NULL,row_no INT NOT NULL,column_name VARCHAR(128),error_code VARCHAR(64) NOT NULL,error_message VARCHAR(500) NOT NULL,created_at DATETIME(3) NOT NULL,KEY idx_error_batch(batch_id));
